import React, { useState } from 'react';

const App = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [passwordVisible, setPasswordVisible] = useState(false);
  const [passwordStrength, setPasswordStrength] = useState('Low');

  const handleToggle = () => {
    setPasswordVisible(!passwordVisible);
  };

  const handleStrength = () => {
    const strength = password.length > 6 ? 'Medium' : 'Low';
    setPasswordStrength(strength);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#C06C88] p-4 rounded-md text-center">
        <input
          type="text"
          value={username}
          onChange={(e) => setUsername(e.target.value)}
          className="bg-[#B7D7CD] p-2 rounded-md w-1/2 mb-4 focus:outline-none focus:ring focus:ring-[#411C56]">
        <input
          type={passwordVisible ? "text" : "password"}
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          className="bg-[#B7D7CD] p-2 rounded-md w-1/2 mb-4 focus:outline-none focus:ring focus:ring-[#411C56]"
        />
        <button
          className="bg-[#B7D7CD] p-2 rounded-md w-1/2 mb-4 focus:outline-none focus:ring focus:ring-[#411C56] hover:bg-[#411C56] hover:text-[#B7D7CD]">
          Login
        </button>
        <button
          className="bg-[#B7D7CD] p-2 rounded-md w-1/2 mb-4 focus:outline-none focus:ring focus:ring-[#411C56] hover:bg-[#411C56] hover:text-[#B7D7CD]"
          onClick={handleToggle}
        >
          {passwordVisible ? "Hide" : "Show"}
        </button>
        <span className="text-[#411C56]">
          Strength: {passwordStrength}
        </span>
      </div>
    </div>
  );
};

export default App;
